const key = $input.first().json.headers?.['x-n8n-key'];
if (key !== $env.N8N_API_KEY) throw new Error('Unauthorized');
return $input.all();

// Check if there's a file to extract or just text/instructions
const body = $('📥 Webhook Fill').first().json.body;
const hasFile = body.hasFile === 'true' || body.hasFile === true;
return [{ json: { body, hasFile } }];

// Build prompt for text-only mode (instructions)
const body = $('📥 Webhook Fill').first().json.body;
return [{ json: {
  fileType: 'text',
  text: body.instructions || body.content || '',
  fileName: 'instructions.txt',
} }];

const body = $('📥 Webhook Fill').first().json.body;
const posts = $('📋 Get Emission Posts').first().json;

let extracted;
try { extracted = $('📂 Extraire texte fichier').first().json; } catch { extracted = null; }
if (!extracted) extracted = $('📝 Utiliser texte direct').first().json;

const postName = body.post_name || '';
const postScope = body.post_scope || '3';
const postDesc = body.post_desc || '';
const instructions = body.instructions || '';
const yearParam = parseInt(body.study_year);
const year = isNaN(yearParam) ? new Date().getFullYear() : yearParam;

const VALID_UNITS = ['kWh','MWh','GJ','m³','L','tonne','kg','km','passager.km','tonne.km','unité','heure'];
const validPeriods = [
  `Année ${year} complète`,
  `T1 ${year} (Jan-Mar)`,
  `T2 ${year} (Avr-Jun)`,
  `T3 ${year} (Jul-Sep)`,
  `T4 ${year} (Oct-Déc)`,
];

const contentSection = extracted.fileType === 'image'
  ? '(voir image ci-jointe)'
  : (extracted.text || instructions || '').slice(0, 10000);

const prompt = `Tu es un expert en comptabilité carbone (méthode Bilan Carbone® BC2025 / ADEME).

Poste cible : ${postName} (Scope ${postScope})${postDesc ? '\nDescription : ' + postDesc : ''}
${instructions ? '\nInstructions : ' + instructions : ''}

Contenu du document :
---
${contentSection}
---

Extrais les informations pertinentes pour CE poste uniquement.
Réponds UNIQUEMENT avec ce JSON strict (sans markdown, sans texte avant/après) :
{
  "description": "Description courte et précise",
  "quantity": 0.0,
  "unit": "kWh",
  "period": "${validPeriods[0]}",
  "factor_query": "mots-clés recherche ADEME"
}

Contraintes :
- unit : EXACTEMENT une de ces valeurs : ${VALID_UNITS.join(', ')}
- period : EXACTEMENT une de ces valeurs : ${validPeriods.join(' | ')}
- quantity : nombre décimal positif uniquement
- description : max 120 caractères, factuelle
- factor_query : 2-5 mots-clés pour chercher le bon facteur d'émission ADEME`;

return [{ json: { prompt, extracted, validPeriods, VALID_UNITS, year } }];

const raw = $input.first().json.choices?.[0]?.message?.content ?? '';
const promptData = $('🧠 Build Prompt Fill').first().json;

const { validPeriods, VALID_UNITS } = promptData;

const match = raw.match(/\{[\s\S]*\}/);
let parsed = {};
try { parsed = JSON.parse(match?.[0] ?? '{}'); } catch {}

const result = {
  description: String(parsed.description ?? '').slice(0, 120),
  quantity: Number(parsed.quantity) || 0,
  unit: VALID_UNITS.includes(parsed.unit) ? parsed.unit : 'kWh',
  period: validPeriods.includes(parsed.period) ? parsed.period : validPeriods[0],
  factor_query: String(parsed.factor_query ?? '').slice(0, 80),
};

return [{ json: result }];
